#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

#define MAXN 1005
#define MAXQ 1005

int N, Q;
int wealth[MAXN];
bool dead[MAXN];
int tin[MAXN], tout[MAXN];
int timer;
int parent[MAXN];
int depthArr[MAXN];
int adj[MAXN][MAXN];
int deg[MAXN];

void dfs(int u, int p) {
    tin[u] = ++timer;
    parent[u] = p;
    for (int i = 0; i < deg[u]; ++i) {
        int v = adj[u][i];
        if (v == p) continue;
        depthArr[v] = depthArr[u] + 1;
        dfs(v, u);
    }
    tout[u] = timer;
}

int main() {
    int T; 
    if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        scanf("%d", &N);
        for (int i = 1; i <= N; ++i) {
            scanf("%d", &wealth[i]);
            dead[i] = false;
            deg[i] = 0;
        }
        for (int i = 0; i < N-1; ++i) {
            int u, v; scanf("%d %d", &u, &v);
            adj[u][deg[u]++] = v;
            adj[v][deg[v]++] = u;
        }
        timer = 0;
        depthArr[1] = 0;
        dfs(1, 0);
        scanf("%d", &Q);
        while (Q--) {
            int type; scanf("%d", &type);
            if (type == 1) {
                int A, X; scanf("%d %d", &A, &X);
                // BFS queue
                int qnode[MAXN];
                int qdist[MAXN];
                int head = 0, tail = 0;
                qnode[tail] = A; qdist[tail++] = 0;
                int visited[MAXN] = {0};
                visited[A] = 1;
                while (head < tail) {
                    int u = qnode[head];
                    int d = qdist[head++];
                    int dmg = X >> d; // X / 2^d
                    if (dmg == 0) continue; // no further effect
                    wealth[u] -= dmg;
                    if (!dead[u] && wealth[u] <= 0) dead[u] = true;
                    for (int i = 0; i < deg[u]; ++i) {
                        int v = adj[u][i];
                        if (!visited[v]) {
                            visited[v] = 1;
                            qnode[tail] = v;
                            qdist[tail++] = d + 1;
                        }
                    }
                }
            } else if (type == 2) {
                int A; scanf("%d", &A);
                int cnt = 0;
                for (int i = 1; i <= N; ++i) {
                    if (dead[i] && tin[A] <= tin[i] && tin[i] <= tout[A]) cnt++;
                }
                printf("%d\n", cnt);
            }
        }
    }
    return 0;
}

