// COMPLETE, COMPILABLE C++ code
#include <bits/stdc++.h>
using namespace std;

const int MAXN = 1005;
int N, Q;
int wealth[MAXN];
bool dead[MAXN];
int tin[MAXN], tout[MAXN];
int timer;
vector<int> adj[MAXN];

void dfs(int u, int p) {
    tin[u] = ++timer;
    for (int v : adj[u]) if (v != p) {
        dfs(v, u);
    }
    tout[u] = timer;
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        cin>>N;
        for(int i=1;i<=N;++i){
            cin>>wealth[i];
            dead[i]=false;
            adj[i].clear();
        }
        for(int i=0;i<N-1;++i){
            int u,v;cin>>u>>v;
            adj[u].push_back(v);
            adj[v].push_back(u);
        }
        timer=0; dfs(1,0);
        cin>>Q;
        while(Q--){
            int type;cin>>type;
            if(type==1){
                int A,X;cin>>A>>X;
                queue<pair<int,int>> q;
                vector<char> vis(N+1,0);
                q.emplace(A,0);
                vis[A]=1;
                while(!q.empty()){
                    auto [u,d]=q.front();q.pop();
                    int dmg = X>>d; // floor division by 2^d
                    if(dmg==0) continue;
                    wealth[u]-=dmg;
                    if(!dead[u] && wealth[u]<=0) dead[u]=true;
                    for(int v:adj[u]) if(!vis[v]){
                        vis[v]=1;
                        q.emplace(v,d+1);
                    }
                }
            }else{ // type 2
                int A;cin>>A;
                int cnt=0;
                for(int i=1;i<=N;++i){
                    if(dead[i] && tin[A]<=tin[i] && tin[i]<=tout[A]) ++cnt;
                }
                cout<<cnt<<"\n";
            }
        }
    }
    return 0;
}
